sEnvironment = Upper(Trim(pEnvironment));
sGroupName = Trim(pGroupName);
sStrictMode = Upper(Trim(pStrictMode));
sLogToCube = Upper(Trim(pLogToCube));
sLogFile = Trim(pLogFile);
If((sGroupName @= '') % (SubSt(sGroupName, 1, 4) @<> 'IMF_')); ProcessBreak; EndIf;
# TODO: Replace this placeholder with an actual group existence check against TM1 or the external identity provider.
sGroupExists = 'N';
If(sGroupExists @= 'Y');
  ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'GROUP_VALIDATE', 'pObjectType', 'GROUP', 'pObjectName', sGroupName, 'pStatus', 'INFO', 'pMessage', 'Group already exists.', 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
ElseIf(sStrictMode @= 'Y');
  ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'GROUP_VALIDATE', 'pObjectType', 'GROUP', 'pObjectName', sGroupName, 'pStatus', 'ERROR', 'pMessage', 'Required IMF group missing. Strict mode abort.', 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
  ProcessBreak;
Else;
  ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'GROUP_VALIDATE', 'pObjectType', 'GROUP', 'pObjectName', sGroupName, 'pStatus', 'WARN', 'pMessage', 'Group missing; continuing because strict mode is disabled. TODO: implement real creation or validation.', 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
EndIf;
